@tailwind base;
@tailwind components;
@tailwind utilities;

body {
  min-width: 1024px;
}

@layer utilities {
  .gradient-text {
    background: linear-gradient(90deg, #496b5a 0%, #b46d32 70%, #2f3432 100%);
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
  }

  .card-surface {
    background: rgba(255, 255, 255, 0.78);
    border: 1px solid #ddd7cb;
    box-shadow: 0 16px 44px rgba(28, 25, 18, 0.06);
    backdrop-filter: blur(6px);
    -webkit-backdrop-filter: blur(6px);
  }

  .card-inset {
    background: #ffffff;
    border: 1px solid #eee8dc;
  }

  .ring-focus:focus-visible {
    outline: none;
    box-shadow: 0 0 0 2px rgba(73, 107, 90, 0.45);
  }

  .btn-primary {
    background-color: #496b5a;
    color: #ffffff;
    transition: background-color 0.15s ease, box-shadow 0.15s ease, transform 0.1s ease;
    box-shadow: 0 8px 20px -10px rgba(73, 107, 90, 0.5);
  }
  .btn-primary:hover:not(:disabled) {
    background-color: #3e5d4d;
    box-shadow: 0 10px 24px -10px rgba(73, 107, 90, 0.55);
  }
  .btn-primary:active:not(:disabled) {
    transform: translateY(1px);
  }

  .btn-ghost {
    background: rgba(255, 255, 255, 0.7);
    border: 1px solid #ddd7cb;
    color: #171512;
    transition: background 0.15s ease, border-color 0.15s ease;
  }
  .btn-ghost:hover:not(:disabled) {
    background: #f2eee6;
    border-color: #b8a98c;
  }

  .input-base {
    background: #ffffff;
    border: 1px solid #ddd7cb;
    color: #171512;
    transition: border-color 0.15s ease, box-shadow 0.15s ease;
  }
  .input-base:hover {
    border-color: #b8a98c;
  }
  .input-base:focus {
    outline: none;
    border-color: #496b5a;
    box-shadow: 0 0 0 3px rgba(73, 107, 90, 0.15);
  }

  .scrollbar-thin::-webkit-scrollbar {
    width: 8px;
    height: 8px;
  }
  .scrollbar-thin::-webkit-scrollbar-thumb {
    background: rgba(112, 107, 97, 0.4);
    border-radius: 999px;
  }
  .scrollbar-thin::-webkit-scrollbar-track {
    background: transparent;
  }
}

