              <ul className="mt-1.5 list-disc list-inside text-zinc-400 space-y-0.5">
                {c.outline.map((o, j) => <li key={j}>{o}</li>)}
              </ul>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
